class Solution:
    def maxSum(self, nums, k):
        MOD = 10 ** 9 + 7
        cnt = [0] * 31
        for x in nums:
            for b in range(31):
                if (x >> b) & 1:
                    cnt[b] += 1
        res = [0] * k
        for b in reversed(range(31)):
            c = cnt[b]
            take = c if c < k else k
            for i in range(take):
                res[i] |= (1 << b)
        total = 0
        for v in res:
            total = (total + v * v) % MOD
        return total

