class Solution:
    def maxSum(self, nums, k):
        MOD = 10 ** 9 + 7
        cnt = [0] * 31
        for x in nums:
            for b in range(31):
                if x & (1 << b):
                    cnt[b] += 1
        total = 0
        for _ in range(k):
            num = 0
            for b in range(31):
                if cnt[b] > 0:
                    num |= (1 << b)
                    cnt[b] -= 1
            total = (total + num * num) % MOD
        return total

