var maxSum = function(nums, k) {
    const MOD = 1000000007n;
    const cnt = new Array(31).fill(0);
    for (const x of nums) {
        for (let b = 0; b < 31; b++) {
            if (x & (1 << b)) cnt[b]++;
        }
    }
    let total = 0n;
    for (let t = 0; t < k; t++) {
        let num = 0;
        for (let b = 0; b < 31; b++) {
            if (cnt[b] > 0) {
                num |= (1 << b);
                cnt[b]--;
            }
        }
        const bn = BigInt(num);
        total = (total + bn * bn) % MOD;
    }
    return Number(total);
};
